$updatedCount = 0;
$failedCount = 0;

$stmt = $db->prepare("UPDATE donation_causes SET history = ?, significance = ?, benefits = ? WHERE id = ?");

foreach ($ekadashis as $id => $data) {
    try {
        $stmt->execute([$data['history'], $data['significance'], $data['benefits'], $id]);
        $updatedCount++;
        echo "  [OK] {$data['slug']} (id={$id})\n";
    } catch (PDOException $e) {
        $failedCount++;
        echo "  [FAIL] {$data['slug']}: " . $e->getMessage() . "\n";
    }
}

echo "\n=== Summary ===\n";
echo "Updated: {$updatedCount}\n";
echo "Failed: {$failedCount}\n";

// Verify
echo "\n=== Verification ===\n";
$verify = $db->query("SELECT id, slug, title, LENGTH(history) as h_len, LENGTH(significance) as s_len, LENGTH(benefits) as b_len FROM donation_causes WHERE category = 'ekadashi' AND is_active = 1 ORDER BY id");
foreach ($verify->fetchAll() as $row) {
    $allOk = $row['h_len'] > 0 && $row['s_len'] > 0 && $row['b_len'] > 0;
    echo "  " . ($allOk ? '[OK]' : '[!!]') . " {$row['slug']}: hist={$row['h_len']} sig={$row['s_len']} ben={$row['b_len']}\n";
}

echo "\n=== Done! ===\n";
